public:
    string solve(int n) {
        if (n < 0) {
            return "Invalid input: n must be a non-negative integer";
        }
        int a = 0, b = 1;
        string result;
        for (int i = 0; i < n; i++) {
            if (i == 0) {
                result += to_string(a);
            } else if (i == 1) {
                result += to_string(b);
            } else {
                result += to_string(a + b);
                int temp = a;
                a = b;
                b = temp + b;
            }
        }
        return result;
    }
};

int main() {
    Solution solution;
    int n;
    cin >> n;
    string result = solution.solve(n);
    cout << result << endl;
    return 0;
}

